    standards: { surface_metal_nonmetal: [{ citation: '30 CFR 56.11012', summary: 'Protection for openings above, below, or near surface M/NM travelways.', evidence: ['opening and travelway geometry', 'fall distance', 'miner travel', 'railing/barrier/cover'] }], underground_metal_nonmetal: [{ citation: '30 CFR 57.11012', summary: 'Protection for openings near underground M/NM travelways.', evidence: ['opening dimensions/location', 'miner travel', 'protective system'] }] },
