    standards: { surface_metal_nonmetal: [{ citation: '30 CFR 56.9100', summary: 'Surface M/NM traffic control and rules governing movement.', evidence: ['traffic interaction', 'rules/signals', 'route and right-of-way', 'miner exposure'] }, { citation: '30 CFR 56.14132(a)', summary: 'Horns and backup alarms on surface M/NM mobile equipment.', evidence: ['equipment type', 'obstructed view/backing', 'alarm/horn function', 'exposure'] }], underground_metal_nonmetal: [{ citation: '30 CFR 57.9100', summary: 'Underground M/NM traffic control and movement rules.', evidence: ['underground haulage context', 'traffic interaction', 'rules/signals'] }, { citation: '30 CFR 57.14132(a)', summary: 'Underground M/NM horns and backup alarms.', evidence: ['equipment and visibility', 'warning-device function', 'miner exposure'] }] },
